mapper.select:
select nd.id, nd.disaster_no as disasterNo, nd.is_historic as isHistoric, nd.classfication_key as classificationKey, nd.disaster_group as disasterGroup, nd.disaster_type as disasterType, nd.disaster_subtype as disasterSubtype, nd.external_ids as externalIds, nd.event_name as eventName, nd.iso, nd.country, nd.subregion, nd.region, nd.location, nd.origin, nd.associated_types as associatedTypes, nd."is_ofda/bha_response" as isOFDAOrBHAResponse, nd.is_appeal as isAppeal, nd.is_declaration as isDeclaration, nd.aid_contribution as aidContribution, nd.magnitude, nd.magnitude_scale as magnitudeScale, nd.latitude, nd.longitude, nd.river_basin as riverBasin, nd.start_year as startYear, nd.start_month as startMonth, nd.start_day as startDay, nd.end_year as endYear, nd.end_month as endMonth, nd.end_day as endDay, nd.total_deaths as totalDeaths, nd.no_injured as noInjured, nd.no_affected as noAffected, nd.no_homeless as noHomeless, nd.total_affected as totalAffected, nd.resonctruction_costs as reconstructionCosts, nd.reconstruction_costs_adjusted as reconstructionCostsAdjusted, nd.insured_damage as insuredDamage, nd.insured_damage_adjusted as insuredDamageAdjusted, nd.total_damage as totalDamage, nd.total_damage_adjusted as totalDamageAdjusted, nd.cpi, nd.admin_units as adminUnits, nd.entry_date as entryDate, nd.last_update as lastUpdate, nd.disaster_subgroup as disasterSubgroup, nd.img_path as imgPath, nd.description from natural_disaster nd
nd.longitude is not null and nd.latitude is not null
and nd.country like '%' || #{country} || '%'
and nd.location like '%' || #{place} || '%'
and nd.disaster_type like '%' || #{type} || '%'
and (nd.start_year || '-' || LPAD(nd.start_month::text, 2, '0') || '-' || LPAD(nd.start_day::text, 2, '0') || ' 00:00:00')::timestamp >= #{begin_date}
and (nd.start_year || '-' || LPAD(nd.start_month::text, 2, '0') || '-' || LPAD(nd.start_day::text, 2, '0') || ' 23:59:59')::timestamp <= #{end_date}
order by nd.id limit #{page_size} offset #{offset}

select img.id, img.img_path as imgPath, img.time, ST_AsGeoJSON(img.geometry) as geometry, img.img_type as imgType, img.longitude, img.latitude from img where natural_disaster_id = #{id}
and img_type = #{img_type}
order by img.id
